UPDATE template_items SET name_vi = 'Lối vào & Khóa cửa phòng máy', standard_vi = 'Lối vào phòng máy thông thoáng không vướng vật cản; Cửa phòng máy khóa đồng bộ, ngoài cửa có biển cảnh báo' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'A5') AND item_number = 1 AND item_name = '机房通道与门锁';
UPDATE template_items SET name_vi = 'Máy kéo', standard_vi = 'Vận hành êm không rung động & tiếng ồn bất thường, mức dầu bôi trơn bình thường, hộp giảm tốc không rò rỉ, phanh hoạt động linh hoạt tin cậy' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'A5') AND item_number = 2 AND item_name = '曳引机';
UPDATE template_items SET name_vi = 'Tủ điều khiển', standard_vi = 'Hiển thị thông số vận hành bình thường, biến tần hoạt động bình thường, đấu nối ngay ngắn chắc chắn, trong tủ sạch sẽ' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'A5') AND item_number = 3 AND item_name = '控制屏柜';
UPDATE template_items SET name_vi = 'Cáp thép', standard_vi = 'Nhãn rõ ràng, không đứt sợi bong bện mòn nặng hoặc rỉ sét, lực căng đều, đầu cáp liên kết chắc chắn' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'A5') AND item_number = 4 AND item_name = '钢丝绳';
UPDATE template_items SET name_vi = 'Bộ hạn chế tốc độ', standard_vi = 'Hoạt động bình thường, niêm phong nguyên vẹn, trong hạn kiểm định, chức năng thử nghiệm liên động bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'A5') AND item_number = 5 AND item_name = '限速器';
UPDATE template_items SET name_vi = 'Khóa liên động cửa tầng', standard_vi = 'Khóa liên động điện các tầng hiệu quả, chức năng tự đóng cửa tầng bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'A5') AND item_number = 6 AND item_name = '层门联锁';
UPDATE template_items SET name_vi = 'Ca-bin', standard_vi = 'Không trầy xước, thông gió chiếu sáng tốt, đèn khẩn cấp hoạt động, thiết bị đàm thoại/báo động liên lạc rõ với phòng trực' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'A5') AND item_number = 7 AND item_name = '轿厢';
UPDATE template_items SET name_vi = 'Thiết bị chống quá tải', standard_vi = 'Chức năng chống quá tải bình thường, khi quá tải báo động âm thanh & ánh sáng chính xác, thang máy không thể đóng cửa khởi động' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'A5') AND item_number = 8 AND item_name = '超载装置';
UPDATE template_items SET name_vi = 'Hố thang', standard_vi = 'Hố thang phẳng sạch, không đọng nước rò rỉ, hệ thống bơm thoát nước hiệu quả, công tắc dừng khẩn cấp & đèn chiếu sáng hoạt động' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'A5') AND item_number = 9 AND item_name = '底坑';
UPDATE template_items SET name_vi = 'Thông gió & Làm mát', standard_vi = 'Thiết bị thông gió làm mát phòng máy bình thường, nhiệt độ môi trường 5~40℃, bố trí cửa gió lá sách' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'A5') AND item_number = 10 AND item_name = '通风降温';
UPDATE template_items SET name_vi = 'Đèn khẩn cấp & PCCC', standard_vi = 'Đèn khẩn cấp nguyên vẹn; bình chữa cháy được trang bị đầy đủ & trong hạn sử dụng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'A5') AND item_number = 11 AND item_name = '应急照明及消防';
UPDATE template_items SET name_vi = 'Tài liệu & Ký hiệu', standard_vi = 'Giấy phép sử dụng / Chứng nhận an toàn thang máy còn hạn, biển hướng dẫn cứu hộ dán rõ ràng, trong phòng máy treo quy trình vận hành' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'A5') AND item_number = 12 AND item_name = '文件与标识';
UPDATE template_items SET name_vi = 'Màn hình giám sát', standard_vi = 'Hình ảnh rõ nét, màu sắc bình thường, không điểm chết, chức năng chia màn hình bình thường, chuyển đổi tuần tra bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B1') AND item_number = 1 AND item_name = '监视器/显示器';
UPDATE template_items SET name_vi = 'Đầu ghi hình (NVR/DVR)', standard_vi = 'Dung lượng lưu trữ đáp ứng ghi hình liên tục ≥ 30 ngày, chức năng phát lại bình thường, đồng bộ thời gian chính xác' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B1') AND item_number = 2 AND item_name = '硬盘录像机(NVR/DVR)';
UPDATE template_items SET name_vi = 'Camera', standard_vi = 'Tất cả camera hình ảnh rõ nét ổn định (ngày/đêm), phạm vi bao phủ không góc chết, lắp đặt chắc chắn' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B1') AND item_number = 3 AND item_name = '摄像头';
UPDATE template_items SET name_vi = 'UPS - Bộ lưu điện', standard_vi = 'Chuyển mạch bình thường, thời gian lưu điện ≥ 30 phút, ắc quy không lão hóa' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B1') AND item_number = 4 AND item_name = 'UPS不间断电源';
UPDATE template_items SET name_vi = 'Hệ thống kiểm soát truy cập', standard_vi = 'Đầu đọc thẻ, khóa điện hoạt động bình thường, bộ điều khiển cửa truyền thông bình thường, chức năng mở cửa liên động PCCC hiệu quả' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B1') AND item_number = 5 AND item_name = '门禁系统';
UPDATE template_items SET name_vi = 'Hệ thống báo động vành đai', standard_vi = 'Hồng ngoại đối xạ/hàng rào điện tử lắp đặt nguyên vẹn, tín hiệu báo động truyền về trung tâm giám sát, chức năng liên động với giám sát bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B1') AND item_number = 6 AND item_name = '周界报警系统';
UPDATE template_items SET name_vi = 'Phần mềm hệ thống', standard_vi = 'Phần mềm hệ thống có đặt mật khẩu, có chức năng phân quyền người vận hành; đã sao lưu 01 bộ phần mềm cài đặt' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B1') AND item_number = 7 AND item_name = '系统软件';
UPDATE template_items SET name_vi = 'Sàn chống tĩnh điện', standard_vi = 'Nguyên vẹn, tiếp địa tin cậy, không hư hỏng bong tróc' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B1') AND item_number = 8 AND item_name = '防静电地板';
UPDATE template_items SET name_vi = 'Điều hòa / Thông gió', standard_vi = 'Nhiệt độ < 30℃, thông gió tốt, điều hòa hoạt động bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B1') AND item_number = 9 AND item_name = '空调/通风';
UPDATE template_items SET name_vi = 'Đèn khẩn cấp & PCCC', standard_vi = 'Đèn khẩn cấp hoạt động 100%; bình chữa cháy được trang bị đầy đủ & trong hạn sử dụng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B1') AND item_number = 10 AND item_name = '应急照明及消防';
UPDATE template_items SET name_vi = 'Đường chính', standard_vi = 'Mặt đường bằng phẳng, không ổ gà, không nứt diện rộng, mặt bê tông không bong tróc, vạch kẻ đường rõ ràng nguyên vẹn' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B2') AND item_number = 1 AND item_name = '主干道';
UPDATE template_items SET name_vi = 'Đường nhánh / Vỉa hè', standard_vi = 'Lát nền nguyên vẹn, không lỏng lẻo bong tróc, gạch lát nền là gạch chống trượt, bằng phẳng không đọng nước' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B2') AND item_number = 2 AND item_name = '支路/人行道';
UPDATE template_items SET name_vi = 'Gờ giảm tốc', standard_vi = 'Đường chính có gờ giảm tốc, lắp đặt chắc chắn, chiều cao đúng quy chuẩn' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B2') AND item_number = 3 AND item_name = '减速坡';
UPDATE template_items SET name_vi = 'Mặt sân bãi đỗ xe', standard_vi = 'Bằng phẳng, không bong cát, không hư hỏng, vạch kẻ rõ ràng, số hiệu chỗ đỗ xe rõ ràng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B2') AND item_number = 4 AND item_name = '停车场地面';
UPDATE template_items SET name_vi = 'Tiện ích bãi đỗ xe', standard_vi = 'Vạch kẻ chỗ đỗ xe đúng quy cách, biển chỉ dẫn rõ ràng, chặn bánh xe nguyên vẹn, gương cầu lồi được lắp đặt đầy đủ, camera giám sát bao phủ' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B2') AND item_number = 5 AND item_name = '停车设施';
UPDATE template_items SET name_vi = 'Hệ thống thoát nước', standard_vi = 'Hố ga thu nước mưa, rãnh thoát nước thông thoáng không tắc, nắp rãnh nguyên vẹn, nắp hố ga đường xe nặng có chức năng chống rung' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B2') AND item_number = 6 AND item_name = '排水系统';
UPDATE template_items SET name_vi = 'Đèn đường', standard_vi = 'Đèn đường lắp đặt chắc chắn, cột đèn thẳng đứng, chiếu sáng bao phủ toàn diện, điều khiển đóng ngắt bình thường, tỷ lệ đèn nguyên vẹn ≥98%' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B2') AND item_number = 7 AND item_name = '道路照明';
UPDATE template_items SET name_vi = 'Phân cách đường & Cây xanh', standard_vi = 'Phân cách đường & dải cây xanh nguyên vẹn, bó vỉa không hư hỏng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B2') AND item_number = 8 AND item_name = '道路与绿化隔离';
UPDATE template_items SET name_vi = 'Cây thân gỗ', standard_vi = 'Tỷ lệ sống ≥95%, không sâu bệnh rõ rệt, cọc chống chắc chắn, tán cây nguyên vẹn, không cành khô chết' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B3') AND item_number = 1 AND item_name = '乔木';
UPDATE template_items SET name_vi = 'Cây bụi / Hàng rào xanh', standard_vi = 'Sinh trưởng tốt, không vàng úa diện rộng, cắt tỉa gọn gàng, không sâu bệnh nghiêm trọng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B3') AND item_number = 2 AND item_name = '灌木/绿篱';
UPDATE template_items SET name_vi = 'Thảm cỏ', standard_vi = 'Che phủ tốt, không trơ trụi rõ rệt, không vàng úa diện rộng hoặc cỏ dại mọc um tùm' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B3') AND item_number = 3 AND item_name = '草坪';
UPDATE template_items SET name_vi = 'Hệ thống tưới', standard_vi = 'Đầu phun nguyên vẹn, góc phun đúng, van đóng mở bình thường không rò rỉ, bộ hẹn giờ hoạt động bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B3') AND item_number = 4 AND item_name = '灌溉系统';
UPDATE template_items SET name_vi = 'Bồn hoa / Chậu hoa', standard_vi = 'Thoát nước thông thoáng không đọng, đất không nén chặt, kết cấu bồn hoa nguyên vẹn không hư hỏng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B3') AND item_number = 5 AND item_name = '花池/花槽/花盆';
UPDATE template_items SET name_vi = 'Tiểu cảnh', standard_vi = 'Ghế, bồn hoa, tượng nguyên vẹn không hư hỏng, lắp đặt chắc chắn, bề mặt sạch sẽ' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B3') AND item_number = 6 AND item_name = '景观小品';
UPDATE template_items SET name_vi = 'Bảng thông tin / Biển chỉ dẫn', standard_vi = 'Sơ đồ mặt bằng khu vực được bố trí hợp lý, nhãn tên cây trồng đầy đủ' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B3') AND item_number = 7 AND item_name = '信息栏/标识牌';
UPDATE template_items SET name_vi = 'Kết cấu tường rào', standard_vi = 'Kết cấu vững chắc, không nghiêng, không nứt, mặt tường nguyên vẹn, sơn phẳng đồng màu' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B4') AND item_number = 1 AND item_name = '围墙结构';
UPDATE template_items SET name_vi = 'Hàng rào / Tường chắn', standard_vi = 'Lắp đặt chắc chắn, mối hàn nhẵn, không bong sơn, gỉ sét, biến dạng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B4') AND item_number = 2 AND item_name = '围栏/护墙';
UPDATE template_items SET name_vi = 'Cổng chính', standard_vi = 'Đóng mở linh hoạt không kẹt, thân cổng không biến dạng rỉ sét, liên động kiểm soát vào ra bình thường, sơn mịn đều màu' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B4') AND item_number = 3 AND item_name = '主入口大门';
UPDATE template_items SET name_vi = 'Cổng phụ / Cổng PCCC', standard_vi = 'Nguyên vẹn không hư hỏng, chiều mở đúng, không bị chặn khóa, khi khẩn cấp mở được dễ dàng từ bên trong' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B4') AND item_number = 4 AND item_name = '侧门/消防通道门';
UPDATE template_items SET name_vi = 'Phòng bảo vệ / Chốt gác', standard_vi = 'Diện tích đáp ứng nhu cầu, điện nước đầy đủ, mạng viễn thông bình thường, tầm nhìn thoáng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B4') AND item_number = 5 AND item_name = '门卫室/岗亭';
UPDATE template_items SET name_vi = 'Thiết bị chống trèo / Chống trộm', standard_vi = 'Hàng rào chống trèo/dây thép gai trên đỉnh tường nguyên vẹn, camera giám sát bao phủ xung quanh tường rào' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B4') AND item_number = 6 AND item_name = '防爬/防盗设施';
UPDATE template_items SET name_vi = 'Diện tích', standard_vi = 'Diện tích đúng hợp đồng, phân khu chức năng hợp lý' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B5') AND item_number = 1 AND item_name = '面积';
UPDATE template_items SET name_vi = 'Tường / Sàn / Trần', standard_vi = 'Tường phẳng không nứt thấm nước, sàn phẳng không bong cát, trần không dấu vết thấm dột, sơn đều' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B5') AND item_number = 2 AND item_name = '墙面/地面/天花';
UPDATE template_items SET name_vi = 'Cửa & Cửa sổ', standard_vi = 'Cửa & cửa sổ nguyên vẹn, đóng mở linh hoạt, khóa bình thường, kính không vỡ, gioăng cao su nguyên vẹn' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B5') AND item_number = 3 AND item_name = '门窗';
UPDATE template_items SET name_vi = 'Cấp nước', standard_vi = 'Nước máy đã đấu nối, vòi nước nguyên vẹn, thoát nước thông thoáng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B5') AND item_number = 4 AND item_name = '供水';
UPDATE template_items SET name_vi = 'Cấp điện', standard_vi = 'Điện đã đấu nối, tủ điện nguyên vẹn, công tắc ổ cắm có điện bình thường, đèn chiếu sáng bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B5') AND item_number = 5 AND item_name = '供电';
UPDATE template_items SET name_vi = 'Thông gió / Điều hòa', standard_vi = 'Thông gió tự nhiên tốt, lỗ chờ điều hòa/sàn đặt dàn nóng đúng quy cách; Phòng ngầm có thiết bị thông gió' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B5') AND item_number = 6 AND item_name = '通风/空调';
UPDATE template_items SET name_vi = 'Liên lạc / Mạng', standard_vi = 'Cổng điện thoại/mạng đã lắp đặt, tín hiệu bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B5') AND item_number = 7 AND item_name = '通讯/网络';
UPDATE template_items SET name_vi = 'PCCC', standard_vi = 'Bình chữa cháy đầy đủ, biển báo thoát hiểm nguyên vẹn' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B5') AND item_number = 8 AND item_name = '消防';
UPDATE template_items SET name_vi = 'Thiết bị vệ sinh', standard_vi = 'Thiết bị vệ sinh / nhà tắm nguyên vẹn, cấp thoát nước thông suốt' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B5') AND item_number = 9 AND item_name = '卫生设施';
UPDATE template_items SET name_vi = 'Thoát khói / Thoát nước', standard_vi = 'Nhà ăn có hệ thống hút khói & thoát nước; Phòng dụng cụ vệ sinh cấp thoát nước đầy đủ thông gió tốt' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B5') AND item_number = 10 AND item_name = '排烟/排水';
UPDATE template_items SET name_vi = 'Mạng lưới cấp nước', standard_vi = 'Đường ống lắp thẳng đứng, cố định chắc chắn; Van tổng cấp nước hoạt động bình thường không rò rỉ; Đồng hồ nước nguyên vẹn' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B6') AND item_number = 1 AND item_name = '供水管网';
UPDATE template_items SET name_vi = 'Mạng lưới thoát nước', standard_vi = 'Thoát nước thông thoáng không tắc nghẽn, hố ga không bồi lắng, nắp hố ga nguyên vẹn ký hiệu rõ ràng, độ dốc thoát nước chính xác' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B6') AND item_number = 2 AND item_name = '排水管网';
UPDATE template_items SET name_vi = 'Hệ thống nước mưa', standard_vi = 'Cửa thu nước mưa/hố ga nước mưa không tắc, ống nước mưa nguyên vẹn, thoát nước mái/mặt đường thông suốt không đọng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B6') AND item_number = 3 AND item_name = '雨水系统';
UPDATE template_items SET name_vi = 'Hệ thống nước thải', standard_vi = 'Ống nước thải thông suốt, bể tự hoại không rò rỉ, thông hơi bình thường, thiết bị xử lý nước thải hoạt động bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B6') AND item_number = 4 AND item_name = '污水系统';
UPDATE template_items SET name_vi = 'Trụ cứu hỏa ngoài trời', standard_vi = 'Lắp chắc chắn, van đóng mở linh hoạt không rò rỉ, áp lực & lưu lượng đáp ứng yêu cầu PCCC' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B6') AND item_number = 5 AND item_name = '室外消火栓';
UPDATE template_items SET name_vi = 'Trụ cứu hỏa trong nhà', standard_vi = 'Lắp chắc chắn, van không rò rỉ, khóa không hư hỏng, dây cứu hỏa & lăng phun đầy đủ, tủ nguyên vẹn' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B6') AND item_number = 6 AND item_name = '室内消火栓';
UPDATE template_items SET name_vi = 'Hệ thống Sprinkler', standard_vi = 'Đầu phun lắp chắc chắn đúng hướng, thiết bị thử nước cuối tuyến bình thường, chuông báo động thủy lực bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B6') AND item_number = 7 AND item_name = '喷淋系统';
UPDATE template_items SET name_vi = 'Ký hiệu mạng lưới ống', standard_vi = 'Các loại mạng lưới ống có ký hiệu chức năng & mũi tên hướng dòng chảy, các van có nhãn ghi rõ phạm vi kiểm soát' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B6') AND item_number = 8 AND item_name = '管网标识';
UPDATE template_items SET name_vi = 'Van xả khí tự động', standard_vi = 'Hệ thống trụ cứu hỏa có lắp thiết bị xả khí tự động ở vị trí cao nhất, chức năng bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B6') AND item_number = 9 AND item_name = '自动排气阀';
UPDATE template_items SET name_vi = 'Trụ cứu hỏa thử nghiệm', standard_vi = 'Trên mái có lắp trụ cứu hỏa thử nghiệm, chức năng bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B6') AND item_number = 10 AND item_name = '试验消火栓';
UPDATE template_items SET name_vi = 'Chống ăn mòn đường ống', standard_vi = 'Đường ống lắp nổi sơn chống rỉ & sơn phủ đúng quy cách, giá đỡ không rỉ sét' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'B6') AND item_number = 11 AND item_name = '管道防腐';
UPDATE template_items SET name_vi = 'Sàn', standard_vi = 'Nền xi măng phẳng đều màu không bong rỗng nứt tróc cát. Gạch men lát phẳng khít mạch không bong rỗng nứt. Miệng thu nước thấp hơn mặt nền 0,5cm viền gọn mịn' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C1') AND item_number = 1 AND item_name = '地面';
UPDATE template_items SET name_vi = 'Tường', standard_vi = 'Tường vữa xi măng phẳng không bong nứt. Tường sơn latex không nứt ố bẩn ố kiềm đều màu. Gạch men ốp tường phẳng khít mạch chà ron đầy đều' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C1') AND item_number = 2 AND item_name = '墙面';
UPDATE template_items SET name_vi = 'Trần nhà', standard_vi = 'Trần thô phẳng không bong rỗng nứt. Trần sơn latex không nứt ố bẩn ố kiềm. Trần thạch cao lắp chắc phẳng chỉ thẳng. Đường góc trong rõ thẳng không khuyết' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C1') AND item_number = 3 AND item_name = '天花/顶棚';
UPDATE template_items SET name_vi = 'Cửa chính', standard_vi = 'Cánh cửa đóng mở êm không ồn vuông góc với khung phẳng khít không biến dạng. Khóa linh hoạt phụ kiện đầy đủ. Sơn bóng đều màu không xước' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C1') AND item_number = 4 AND item_name = '入户门';
UPDATE template_items SET name_vi = 'Cửa sổ', standard_vi = 'Kính nguyên vẹn không bọt sóng keo đều gioăng không thiếu. Đóng mở linh hoạt gioăng kín nguyên vẹn. Khung cửa sổ không biến dạng rỉ sét không thấm' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C1') AND item_number = 5 AND item_name = '窗户';
UPDATE template_items SET name_vi = 'Lỗ chừa sẵn', standard_vi = 'Lỗ chờ điều hòa, máy hút mùi, bình nước nóng không thiếu vị trí hợp lý. Miệng lỗ trong cao ngoài thấp dốc ~10° không cản trở viền phẳng mịn' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C1') AND item_number = 6 AND item_name = '预留孔';
UPDATE template_items SET name_vi = 'Đầu nối chừa sẵn', standard_vi = 'Đầu chờ ống nước nóng lạnh, ống gas, ống nước ngưng điều hòa vị trí đúng độ cao hợp lý. Ống nước ngưng dốc về phía thoát nước, Tê thu nước thử nước không rò rỉ' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C1') AND item_number = 7 AND item_name = '预留接口';
UPDATE template_items SET name_vi = 'Lan can / Tay vịn ban công', standard_vi = 'Liên kết chắc chắn mối hàn nhẵn chỗ tiếp giáp tường phẳng đẹp. Sơn đều đầy không lệch màu nứt bong' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C1') AND item_number = 8 AND item_name = '阳台护栏/拦板';
UPDATE template_items SET name_vi = 'Cầu thang', standard_vi = 'Bậc thang & tay vịn chắc chắn sơn đều nhẵn không rỉ sét. Sai số chiều cao rộng bậc ≤ 15mm gạch chống trượt không hư hỏng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C1') AND item_number = 9 AND item_name = '楼梯';
UPDATE template_items SET name_vi = 'Vệ sinh trong nhà', standard_vi = 'Vệ sinh trong nhà đạt tiêu chuẩn dọn phòng: không còn rác xây dựng, sàn tường sạch sẽ' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C1') AND item_number = 10 AND item_name = '室内清洁';
UPDATE template_items SET name_vi = 'Van tổng cấp nước', standard_vi = 'Công tắc bình thường, thao tác linh hoạt, không rò rỉ, vị trí đặt hợp lý thuận tiện thao tác' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C2') AND item_number = 1 AND item_name = '给水分户总阀';
UPDATE template_items SET name_vi = 'Đồng hồ nước', standard_vi = 'Bề ngoài không hư hỏng, lắp đặt chắc chắn, số đọc rõ ràng, mối nối không rò rỉ' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C2') AND item_number = 2 AND item_name = '水表';
UPDATE template_items SET name_vi = 'Ống cấp nước', standard_vi = 'Đường ống lắp chắc chắn không rò rỉ, khoảng cách kẹp ống hợp lý; Ống lắp nổi có nhãn; Áp lực nước đáp ứng nhu cầu' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C2') AND item_number = 3 AND item_name = '给水管道';
UPDATE template_items SET name_vi = 'Ống thoát nước', standard_vi = 'Thoát nước thông suốt không tắc, mối nối ống không rò rỉ, bẫy nước nguyên vẹn, không mùi hôi ngược' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C2') AND item_number = 4 AND item_name = '排水管道';
UPDATE template_items SET name_vi = 'Lưới thu nước sàn', standard_vi = 'Vị trí thu nước sàn hợp lý thoát tốt viền quanh mịn; Nền bếp, WC & ban công dốc về phía thu nước không đọng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C2') AND item_number = 5 AND item_name = '地漏';
UPDATE template_items SET name_vi = 'Thiết bị vệ sinh', standard_vi = 'Chậu rửa / Bồn cầu lắp chắc bề mặt nguyên vẹn không vỡ tróc men; Bẫy nước không rò rỉ thoát tốt có lực hút' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C2') AND item_number = 6 AND item_name = '卫生洁具';
UPDATE template_items SET name_vi = 'Vòi nước / Sen tắm', standard_vi = 'Lắp chắc ngay ngắn đóng mở dễ dàng bề mặt không hư hỏng rỉ sét; Lưu lượng & tốc độ nước ra bình thường không nhỏ giọt' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C2') AND item_number = 7 AND item_name = '水龙头/花洒';
UPDATE template_items SET name_vi = 'Mặt bàn / Tủ bếp', standard_vi = 'Mặt đá phẳng vuông không vỡ ố bẩn keo viền đầy đều; Chỗ tiếp giáp đá & chậu rửa keo kín không rò rỉ' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C2') AND item_number = 8 AND item_name = '台面/地柜';
UPDATE template_items SET name_vi = 'Thiết bị nhà bếp', standard_vi = 'Tủ bếp lắp chắc phụ kiện đầy đủ mặt bếp phẳng bóng; Nút chặn chậu rửa đóng mở linh hoạt không rò rỉ thoát nước tốt' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C2') AND item_number = 9 AND item_name = '厨房设备';
UPDATE template_items SET name_vi = 'Thông gió & Hút mùi', standard_vi = 'Quạt hút gió & van một chiều hoạt động tốt, ống thoát gió nối kín không lọt gió' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C2') AND item_number = 10 AND item_name = '通风排气';
UPDATE template_items SET name_vi = 'Khí đốt / Gas', standard_vi = 'Đường ống gas lắp thẳng chắc chắn chỗ xuyên tường bịt kín; Van tổng từng hộ đóng mở bình thường mối nối kín không rò rỉ' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C2') AND item_number = 11 AND item_name = '煤气/燃气';
UPDATE template_items SET name_vi = 'Tủ điện', standard_vi = 'Lắp chắc vị trí hợp lý vỏ tủ nguyên vẹn không rỉ sét; Đấu nối trong tủ gọn gàng chắc chắn; Nhãn mạch điện rõ ràng; Kiểm tra chống giật bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C3') AND item_number = 1 AND item_name = '配电箱';
UPDATE template_items SET name_vi = 'Đèn chiếu sáng', standard_vi = 'Đèn lắp chắc không lỏng bề mặt sạch nguyên vẹn; Công tắc điều khiển bình thường; Bóng đèn/ống đèn nguyên vẹn đúng chủng loại' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C3') AND item_number = 2 AND item_name = '照明灯具';
UPDATE template_items SET name_vi = 'Công tắc', standard_vi = 'Vị trí lắp hợp lý chắc chắn mặt công tắc nguyên vẹn thao tác thuận tiện, các công tắc tương ứng đúng đèn' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C3') AND item_number = 3 AND item_name = '开关';
UPDATE template_items SET name_vi = 'Ổ cắm', standard_vi = 'Lắp chắc vị trí hợp lý mặt ổ nguyên vẹn; Có điện bình thường, dây pha dây trung tính dây tiếp địa đấu đúng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C3') AND item_number = 4 AND item_name = '插座';
UPDATE template_items SET name_vi = 'Ổ cắm điều hòa', standard_vi = 'Ổ cắm riêng cho điều hòa dòng định mức đáp ứng yêu cầu thiết bị (≥ 15A), vị trí tương ứng lỗ chờ & sàn đặt dàn nóng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C3') AND item_number = 5 AND item_name = '空调插座';
UPDATE template_items SET name_vi = 'Cổng tín hiệu yếu', standard_vi = 'Cổng TV, điện thoại, mạng vị trí hợp lý lắp chắc tín hiệu bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C3') AND item_number = 6 AND item_name = '弱电接口';
UPDATE template_items SET name_vi = 'Chuông cửa / Video doorphone', standard_vi = 'Vị trí hợp lý lắp chắc nguyên vẹn, màn hình hình ảnh rõ ràng đàm thoại bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C3') AND item_number = 7 AND item_name = '门铃/可视对讲';
UPDATE template_items SET name_vi = 'Hệ thống báo động gia đình', standard_vi = 'Theo yêu cầu thiết kế nguyên vẹn, nút khẩn cấp hoạt động, tín hiệu báo động truyền về trung tâm giám sát' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C3') AND item_number = 8 AND item_name = '居家报警系统';
UPDATE template_items SET name_vi = 'Liên kết đẳng thế', standard_vi = 'Hộp đấu đẳng thế trong WC nguyên vẹn, kết nối tin cậy' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C3') AND item_number = 9 AND item_name = '等电位连接';
UPDATE template_items SET name_vi = 'Công tơ điện', standard_vi = 'Mỗi hộ công tơ điện riêng, lắp chắc chắn, số đọc rõ ràng, đấu nối chính xác, niêm phong chì nguyên vẹn' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C3') AND item_number = 10 AND item_name = '电表';
UPDATE template_items SET name_vi = 'Cửa cuốn / Cửa công nghiệp', standard_vi = 'Thân cửa không biến dạng rỉ sét, nâng hạ êm không kẹt; Vận hành tay/điện bình thường; Công tắc hành trình hoạt động bình thường; Gioăng kín nguyên vẹn' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C4') AND item_number = 1 AND item_name = '卷帘门/工业门';
UPDATE template_items SET name_vi = 'Cửa chính / Cửa chống cháy', standard_vi = 'Cánh cửa không biến dạng đóng mở êm; Khóa linh hoạt phụ kiện đầy đủ; Tay đẩy hơi lực vừa phải; Nhãn cấp chống cháy rõ ràng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C4') AND item_number = 2 AND item_name = '入户门/防火门';
UPDATE template_items SET name_vi = 'Tủ điện trong nhà', standard_vi = 'Lắp chắc vỏ tủ nguyên vẹn; Aptomat tổng công suất đúng thiết kế; Đấu nối gọn chắc; Chống giật test bình thường; Nhãn mạch rõ ràng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C4') AND item_number = 3 AND item_name = '室内配电箱';
UPDATE template_items SET name_vi = 'Đèn trong nhà', standard_vi = 'Đèn lắp chắc bề mặt sạch; Công tắc điều khiển bình thường; Độ rọi đáp ứng nhu cầu; Đèn chống nổ đúng thiết kế' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C4') AND item_number = 4 AND item_name = '室内照明';
UPDATE template_items SET name_vi = 'Công tắc & Ổ cắm', standard_vi = 'Lắp chắc vị trí hợp lý; Có điện đấu nối đúng; Loại ổ cắm công nghiệp & cấp bảo vệ IP đúng thiết kế' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C4') AND item_number = 5 AND item_name = '开关插座';
UPDATE template_items SET name_vi = 'Sàn', standard_vi = 'Nền xi măng / epoxy phẳng không bong rỗng nứt bở cát; Xử lý chống mài mòn / chống tĩnh điện / chống ăn mòn theo thiết kế; Độ dốc thoát nước đúng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C4') AND item_number = 6 AND item_name = '地面';
UPDATE template_items SET name_vi = 'Tường', standard_vi = 'Phẳng không nứt không dấu vết thấm nước; Sơn đều không ố kiềm lệch màu; Tường ngăn cháy / vách phân vùng chống cháy đúng thiết kế' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C4') AND item_number = 7 AND item_name = '墙面';
UPDATE template_items SET name_vi = 'Mái / Trần', standard_vi = 'Không dấu vết thấm máng xối thoát nước tốt; Tấm lợp mái không biến dạng hư hỏng; Tấm lấy sáng / quạt thông gió nguyên vẹn; Lớp cách nhiệt nguyên vẹn' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C4') AND item_number = 8 AND item_name = '屋顶/天花';
UPDATE template_items SET name_vi = 'Cửa sổ / Cửa thông gió', standard_vi = 'Kính nguyên vẹn không vỡ; mở linh hoạt; gioăng kín nguyên vẹn; khung cửa không biến dạng gỉ sét; không thấm dột' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C4') AND item_number = 9 AND item_name = '窗户/通风窗';
UPDATE template_items SET name_vi = 'Đầu nối cấp nước', standard_vi = 'Ống cấp nước đã lắp đặt, van đóng mở linh hoạt không rò rỉ; đồng hồ nước nguyên vẹn; áp suất cấp nước đáp ứng nhu cầu sử dụng' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C4') AND item_number = 10 AND item_name = '给水接口';
UPDATE template_items SET name_vi = 'Hệ thống thoát nước', standard_vi = 'Ống thoát nước thông mối nối không rò rỉ; Thu nước sàn vị trí hợp lý thoát tốt; Rãnh thoát nước nhà xưởng độ dốc đúng không tắc; Bể tách dầu / bể lắng hoạt động bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C4') AND item_number = 11 AND item_name = '排水系统';
UPDATE template_items SET name_vi = 'Thiết bị PCCC', standard_vi = 'Đầu phun / Họng cứu hỏa bố trí đúng quy chuẩn lắp đặt đúng; Bình chữa cháy đầy đủ còn hạn; Đầu báo khói / đầu báo nhiệt lắp đúng không điểm bị vô hiệu' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C4') AND item_number = 12 AND item_name = '消防设施';
UPDATE template_items SET name_vi = 'Thông gió / Thoát khói', standard_vi = 'Cửa gió tự nhiên / quạt thông gió nguyên vẹn; Quạt thông gió cơ khí vận hành bình thường lưu lượng gió đạt; Cửa hút khói / van hút khói hoạt động bình thường' WHERE template_id = (SELECT id FROM inspection_templates WHERE form_id = 'C4') AND item_number = 13 AND item_name = '通风/排烟';
